#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding respirology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    chief_complaint:text! \
    onset:string! \
    duration:text! \
    severity:string! \
    dyspnoea:string! \
    cough:string! \
    wheeze:string! \
    chest_pain:string! \
    haemoptysis:string! \
    recurrent_respiratory_infections:string! \
    weight_loss:string! \
    night_sweats:string! \
    fever:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_dyspnoea_assessment \
    assessment:references \
    mrc_dyspnoea_grade:int \
    dyspnoea_at_rest:string! \
    dyspnoea_on_exertion:string! \
    orthopnoea:string! \
    paroxysmal_nocturnal_dyspnoea:string! \
    dyspnoea_onset:string! \
    dyspnoea_triggers:text! \
    dyspnoea_relieving_factors:text! \
    exercise_limitation:string! \
    walking_distance_metres:int \
    flights_of_stairs:int \
    borg_dyspnoea_score:int \
    oxygen_requirement:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cough_assessment \
    assessment:references \
    cough_present:string! \
    cough_duration:string! \
    cough_duration_weeks:int \
    cough_type:string! \
    cough_timing:string! \
    sputum_production:string! \
    sputum_volume:string! \
    sputum_colour:string! \
    sputum_odour:string! \
    haemoptysis:string! \
    haemoptysis_volume:string! \
    cough_triggers:text! \
    cough_impact_on_sleep:string! \
    cough_impact_on_daily_life:string! \
    post_nasal_drip:string! \
    gastro_oesophageal_reflux:string! \
    ace_inhibitor_use:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_respiratory_history \
    assessment:references \
    asthma:string! \
    asthma_age_of_onset:int \
    copd:string! \
    copd_diagnosis_year:int \
    bronchiectasis:string! \
    interstitial_lung_disease:string! \
    ild_type:text! \
    tuberculosis_history:string! \
    tb_treatment_completed:string! \
    pneumothorax_history:string! \
    pulmonary_embolism:string! \
    lung_surgery:string! \
    lung_surgery_details:text! \
    chest_trauma:string! \
    previous_hospitalisations:int \
    previous_intubation:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_pulmonary_function \
    assessment:references \
    spirometry_performed:string! \
    test_date:date \
    fev1_litres:double \
    fev1_predicted_pct:double \
    fvc_litres:double \
    fvc_predicted_pct:double \
    fev1_fvc_ratio:double \
    peak_flow_lmin:int \
    peak_flow_variability_pct:double \
    dlco_pct:double \
    total_lung_capacity_pct:double \
    residual_volume_pct:double \
    bronchodilator_reversibility:string! \
    methacholine_challenge:string! \
    oxygen_saturation_rest:double \
    arterial_blood_gas_performed:string! \
    pao2_kpa:double \
    paco2_kpa:double \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_respiratory_medications:string! \
    inhaler_use:string! \
    inhaler_technique_assessed:string! \
    inhaler_technique_adequate:string! \
    long_term_oxygen_therapy:string! \
    nebuliser_use:string! \
    takes_other_medications:string! \
    medication_adherence:string! \
    adverse_drug_reactions:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    indication:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_allergies \
    assessment:references \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    has_environmental_allergies:string! \
    environmental_allergy_details:text! \
    atopic_history:string! \
    eczema:string! \
    allergic_rhinitis:string! \
    food_allergies:string! \
    food_allergy_details:text! \
    aspirin_sensitivity:string! \
    allergy_testing_performed:string! \
    allergy_test_results:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_smoking_exposures \
    assessment:references \
    smoking_status:string! \
    pack_years:double \
    cigarettes_per_day:int \
    age_started_smoking:int \
    age_stopped_smoking:int \
    vaping:string! \
    vaping_details:text! \
    cannabis_smoking:string! \
    passive_smoke_exposure:string! \
    occupational_exposures:string! \
    occupational_exposure_details:text! \
    asbestos_exposure:string! \
    silica_exposure:string! \
    biomass_fuel_exposure:string! \
    indoor_air_quality_concerns:string! \
    air_quality_details:text! \
    smoking_cessation_advice:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_sleep_functional \
    assessment:references \
    sleep_quality:string! \
    snoring:string! \
    witnessed_apnoeas:string! \
    daytime_sleepiness:string! \
    epworth_sleepiness_score:int \
    sleep_study_performed:string! \
    osa_diagnosed:string! \
    cpap_use:string! \
    cpap_compliance:string! \
    adl_independence:string! \
    mobility_level:string! \
    employment_impact:string! \
    exercise_tolerance:text! \
    quality_of_life_impact:string! \
    pulmonary_rehabilitation:string! \
    advance_care_planning:string! \
    advance_care_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    mrc_grade:int! \
    mrc_description:string! \
    overall_severity:string! \
    functional_impairment:string! \
    composite_score:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
